// Recursive function: factorial of n (n! = n * (n-1) * ... * 1)
function factorial(n: number): number {
  // Base case: factorial of 0 or 1 is 1
  // Without this, recursion would never stop (stack overflow)
  if (n <= 1) {
    return 1;
  }
  // Recursive case: n * factorial of (n-1)
  // Each call reduces n by 1, moving toward the base case
  return n * factorial(n - 1);
}
// Test with 5 (expected: 5 * 4 * 3 * 2 * 1 = 120)
console.log('Factorial of 5:', factorial(5));
// Test edge cases
console.log('Factorial of 0:', factorial(0));
console.log('Factorial of 1:', factorial(1));
// Expected output:
// Factorial of 5: 120
// Factorial of 0: 1
// Factorial of 1: 1
